const d = $json.body ?? $json;

const appName      = d.appName      || '錢錢管家';
const appVersion   = d.appVersion   || '?';
const category     = d.category     || 'General';
const message      = d.message      || '';
const contactEmail = d.contactEmail || '';
const platform     = d.platform     || '';
const osVersion    = d.osVersion    || '';
const deviceModel  = d.deviceModel  || '';
const sourcePage   = d.sourcePage   || '';
const hasImages    = d.hasImages    || 'false';
const createdAt    = d.createdAt    || new Date().toISOString();

const subject = '[' + appName + ' Feedback] ' + category + ' — v' + appVersion;

const body = '=== ' + appName + ' User Feedback ===\n\n'
  + '類別:    ' + category + '\n'
  + '訊息:\n' + message + '\n\n'
  + '聯絡信箱: ' + (contactEmail || '未提供') + '\n'
  + 'App 版本: ' + appName + ' v' + appVersion + '\n'
  + '平台:    ' + platform + ' ' + osVersion + '\n'
  + '裝置:    ' + deviceModel + '\n'
  + '來源頁面: ' + sourcePage + '\n'
  + '附圖:    ' + (hasImages === 'true' ? 'Yes' : 'No') + '\n'
  + '時間:    ' + createdAt + '\n';

return [{ json: { emailSubject: subject, emailBody: body } }];
